const body = $input.first().json.body;
const p = body.product;

const toneInstructions = {
  luxury: 'Schreibe in einem eleganten, exklusiven Luxus-Stil. Betone Qualität, Handwerk und Exklusivität. Verwende gehobene Sprache ohne Übertreibungen.',
  casual: 'Schreibe locker und sympathisch. Direkte Ansprache (du), freundlich und nahbar. Wie eine Empfehlung vom Freund.',
  technical: 'Schreibe technisch präzise. Betone Spezifikationen, Materialien, Normen und messbare Eigenschaften. Sachlich und informativ.'
};

const toneHint = toneInstructions[p.tone] || toneInstructions.casual;

const prompt = `Erstelle eine verkaufsstarke Produktbeschreibung für folgenden Artikel. Antworte NUR mit validem JSON.

Produkt:
- Name: ${p.name}
- Kategorie: ${p.category}
- Preis: ${p.price} EUR
- Lagerbestand: ${p.stock} Stück
- Gewünschter Ton: ${p.tone}

Ton-Anweisung: ${toneHint}

Antworte in exakt diesem JSON-Format:
{
  "description": "2-3 Sätze Produktbeschreibung auf Deutsch. Kein Markdown.",
  "tags": ["3 bis 5 kurze Schlagwörter als Array"]
}

Regeln:
- Beschreibung: 2-3 flüssige Sätze, sprachlich passend zum Ton
- Tags: kurze Substantive oder Adjektive, max. 2 Wörter pro Tag
- Kein Markdown, keine Backticks, reines JSON`;

return [{ json: { prompt, productId: p.id } }];

const aiText = $input.first().json.message?.content || '{}';
const productId = $('Prompt aufbauen').first().json.productId;

let parsed;
try {
  const cleaned = aiText.replace(/```json\n?/g,'').replace(/```/g,'').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = {
    description: 'Beschreibung konnte nicht generiert werden.',
    tags: []
  };
}

// Validierung
if (typeof parsed.description !== 'string') parsed.description = '';
if (!Array.isArray(parsed.tags)) parsed.tags = [];
parsed.tags = parsed.tags.slice(0, 5).map(t => String(t));

return [{ json: {
  description: parsed.description,
  tags: parsed.tags,
  productId
}}];
